1	pub const Parser = struct {
2	    opts: Options = .{},
3	    source: bun.logger.Source,
4	    src: []const u8,
5	    out: Expr,
6	    logger: bun.logger.Log,
7	    arena: std.heap.ArenaAllocator,
8	    env: *bun.DotEnv.Loader,
9	
10	    const Options = struct {
11	        bracked_array: bool = true,
12	    };
13	
14	    pub fn init(allocator: Allocator, path: []const u8, src: []const u8, env: *bun.DotEnv.Loader) Parser {
15	        return .{
16	            .logger = bun.logger.Log.init(allocator),
17	            .src = src,
18	            .out = Expr.init(E.Object, E.Object{}, Loc.Empty),
19	            .source = bun.logger.Source.initPathString(path, src),
20	            .arena = std.heap.ArenaAllocator.init(allocator),
21	            .env = env,
22	        };
23	    }
24	
25	    pub fn deinit(this: *Parser) void {
26	        this.logger.deinit();
27	        this.arena.deinit();
28	    }
29	
30	    inline fn shouldSkipLine(line: []const u8) bool {
31	        if (line.len == 0 or
32	            // comments
33	            line[0] == ';' or
34	            line[0] == '#') return true;
35	
36	        // check the rest is whitespace
37	        for (line) |c| {
38	            switch (c) {
39	                ' ', '\t', '\n', '\r' => {},
40	                '#', ';' => return true,
41	                else => return false,
42	            }
43	        }
44	        return true;
45	    }
46	
47	    fn parse(this: *Parser, arena_allocator: Allocator) OOM!void {
48	        var iter = std.mem.splitScalar(u8, this.src, '\n');
49	        var head: *E.Object = this.out.data.e_object;
50	
51	        // var duplicates = bun.StringArrayHashMapUnmanaged(u32){};
52	        // defer duplicates.deinit(allocator);
53	
54	        var rope_stack = std.heap.stackFallback(@sizeOf(Rope) * 6, arena_allocator);
55	        const ropealloc = rope_stack.get();
56	
57	        var skip_until_next_section: bool = false;
58	
59	        while (iter.next()) |line_| {
60	            const line = if (line_.len > 0 and line_[line_.len - 1] == '\r') line_[0 .. line_.len - 1] else line_;
61	            if (shouldSkipLine(line)) continue;
62	
63	            // Section
64	            // [foo]
65	            if (line[0] == '[') treat_as_key: {
66	                skip_until_next_section = false;
67	                const close_bracket_idx = std.mem.indexOfScalar(u8, line[0..], ']') orelse continue;
68	                // Make sure the rest is just whitespace
69	                if (close_bracket_idx + 1 < line.len) {
70	                    for (line[close_bracket_idx + 1 ..]) |c| if (switch (c) {
71	                        ' ', '\t' => false,
72	                        else => true,
73	                    }) break :treat_as_key;
74	                }
75	                const section: *Rope = try this.prepareStr(arena_allocator, ropealloc, line[1..close_bracket_idx], @as(i32, @intCast(@intFromPtr(line.ptr) - @intFromPtr(this.src.ptr))) + 1, .section);
76	                defer rope_stack.fixed_buffer_allocator.reset();
77	                const parent_object = this.out.data.e_object.getOrPutObject(section, arena_allocator) catch |e| switch (e) {
78	                    error.OutOfMemory => |oom| return oom,
79	                    error.Clobber => {
80	                        // We're in here if key exists but it is not an object
81	                        //
82	                        // This is possible if someone did:
83	                        //
84	                        // ```ini
85	                        // foo = 'bar'
86	                        //
87	                        // [foo]
88	                        // hello = 420
89	                        // ```
90	                        //
91	                        // In the above case, `this.out[section]` would be a string.
92	                        // So what should we do in that case?
93	                        //
94	                        // npm/ini's will chug along happily trying to assign keys to the string.
95	                        //
96	                        // In JS assigning keys to string does nothing.
97	                        //
98	                        // Technically, this would have an effect if the value was an array:
99	                        //
100	                        // ```ini
101	                        // foo[] = 0
102	                        // foo[] = 1
103	                        //
104	                        // [foo]
105	                        // 0 = 420
106	                        // ```
107	                        //
108	                        // This would result in `foo` being `[420, 1]`.
109	                        //
110	                        // To be honest this is kind of crazy behavior so we're just going to skip this for now.
111	                        skip_until_next_section = true;
112	                        continue;
113	                    },
114	                };
115	                head = parent_object.data.e_object;
116	                continue;
117	            }
118	            if (skip_until_next_section) continue;
119	
120	            // Otherwise it's a key val here
121	
122	            const line_offset: i32 = @intCast(@intFromPtr(line.ptr) - @intFromPtr(this.src.ptr));
123	
124	            const maybe_eq_sign_idx = std.mem.indexOfScalar(u8, line, '=');
125	
126	            const key_raw: []const u8 = try this.prepareStr(arena_allocator, ropealloc, line[0 .. maybe_eq_sign_idx orelse line.len], line_offset, .key);
127	            const is_array: bool = brk: {
128	                break :brk key_raw.len > 2 and bun.strings.endsWith(key_raw, "[]");
129	                // Commenting out because options are not supported but we might
130	                // support them.
131	                // if (this.opts.bracked_array) {
132	                //     break :brk key_raw.len > 2 and bun.strings.endsWith(key_raw, "[]");
133	                // } else {
134	                //     // const gop = try duplicates.getOrPut(allocator, key_raw);
135	                //     // if (gop.found_existing) {
136	                //     //     gop.value_ptr.* = 1;
137	                //     // } else gop.value_ptr.* += 1;
138	                //     // break :brk gop.value_ptr.* > 1;
139	                //     @panic("We don't support this right now");
140	                // }
141	            };
142	
143	            const key = if (is_array and bun.strings.endsWith(key_raw, "[]"))
144	                key_raw[0 .. key_raw.len - 2]
145	            else
146	                key_raw;
147	
148	            if (bun.strings.eqlComptime(key, "__proto__")) continue;
149	
150	            const value_raw: Expr = brk: {
151	                if (maybe_eq_sign_idx) |eq_sign_idx| {
152	                    if (eq_sign_idx + 1 < line.len) break :brk try this.prepareStr(
153	                        arena_allocator,
154	                        ropealloc,
155	                        line[eq_sign_idx + 1 ..],
156	                        @intCast(line_offset + @as(i32, @intCast(eq_sign_idx)) + 1),
157	                        .value,
158	                    );
159	                    break :brk Expr.init(E.String, E.String{ .data = "" }, Loc.Empty);
160	                }
161	                break :brk Expr.init(E.Boolean, E.Boolean{ .value = true }, Loc.Empty);
162	            };
163	
164	            const value: Expr = switch (value_raw.data) {
165	                .e_string => |s| if (bun.strings.eqlComptime(s.data, "true"))
166	                    Expr.init(E.Boolean, E.Boolean{ .value = true }, Loc.Empty)
167	                else if (bun.strings.eqlComptime(s.data, "false"))
168	                    Expr.init(E.Boolean, E.Boolean{ .value = false }, Loc.Empty)
169	                else if (bun.strings.eqlComptime(s.data, "null"))
170	                    Expr.init(E.Null, E.Null{}, Loc.Empty)
171	                else
172	                    value_raw,
173	                else => value_raw,
174	            };
175	
176	            if (is_array) {
177	                if (head.get(key)) |val| {
178	                    if (val.data != .e_array) {
179	                        var arr = E.Array{};
180	                        try arr.push(arena_allocator, val);
181	                        try head.put(arena_allocator, key, Expr.init(E.Array, arr, Loc.Empty));
182	                    }
183	                } else {
184	                    try head.put(arena_allocator, key, Expr.init(E.Array, E.Array{}, Loc.Empty));
185	                }
186	            }
187	
188	            // safeguard against resetting a previously defined
189	            // array by accidentally forgetting the brackets
190	            var was_already_array = false;
191	            if (head.get(key)) |val| {
192	                if (val.data == .e_array) {
193	                    was_already_array = true;
194	                    try val.data.e_array.push(arena_allocator, value);
195	                    try head.put(arena_allocator, key, val);
196	                }
197	            }
198	            if (!was_already_array) {
199	                try head.put(arena_allocator, key, value);
200	            }
201	        }
202	    }
