204	    fn prepareStr(
205	        this: *Parser,
206	        arena_allocator: Allocator,
207	        ropealloc: Allocator,
208	        val_: []const u8,
209	        offset_: i32,
210	        comptime usage: enum { section, key, value },
211	    ) OOM!switch (usage) {
212	        .value => Expr,
213	        .section => *Rope,
214	        .key => []const u8,
215	    } {
216	        var offset = offset_;
217	        var val = std.mem.trim(u8, val_, " \n\r\t");
218	
219	        if (isQuoted(val)) out: {
220	            // remove single quotes before calling JSON.parse
221	            if (val.len > 0 and val[0] == '\'') {
222	                val = if (val.len > 1) val[1 .. val.len - 1] else val[1..];
