809	        var base: enum { dec, hex, oct } = .dec;
810	
811	        next: switch (str.charAt(i)) {
812	            '.' => {
813	                if (dot or base != .dec) {
814	                    offset.* = i;
815	                    return false;
816	                }
817	                dot = true;
818	                i += 1;
819	                if (i < str.length()) {
820	                    continue :next str.charAt(i);
821	                }
822	                return true;
823	            },
824	
825	            '+' => {
826	                if (@"+") {
827	                    offset.* = i;
828	                    return false;
829	                }
830	                @"+" = true;
831	                i += 1;
832	                if (i < str.length()) {
833	                    continue :next str.charAt(i);
834	                }
835	                return true;
836	            },
837	
838	            '-' => {
839	                if (@"-") {
840	                    offset.* = i;
841	                    return false;
842	                }
843	                @"-" = true;
844	                i += 1;
845	                if (i < str.length()) {
846	                    continue :next str.charAt(i);
847	                }
848	                return true;
849	            },
850	
851	            '0' => {
852	                if (i == start) {
853	                    if (i + 1 < str.length()) {
854	                        switch (str.charAt(i + 1)) {
855	                            'x', 'X' => {
856	                                base = .hex;
857	                            },
858	                            'o', 'O' => {
859	                                base = .oct;
860	                            },
861	                            '0'...'9' => {
862	                                // 0 prefix allowed
863	                            },
864	                            else => {
865	                                offset.* = i;
866	                                return false;
867	                            },
868	                        }
869	                        i += 1;
870	                    } else {
871	                        return true;
872	                    }
873	                }
874	
875	                i += 1;
876	                if (i < str.length()) {
877	                    continue :next str.charAt(i);
878	                }
879	                return true;
880	            },
881	
882	            'e',
883	            'E',
