885	                if (base == .oct or (e and base == .dec)) {
886	                    offset.* = i;
887	                    return false;
888	                }
889	                e = true;
890	                i += 1;
891	                if (i < str.length()) {
892	                    continue :next str.charAt(i);
893	                }
894	                return true;
895	            },
896	
897	            'a'...'d',
898	            'f',
899	            'A'...'D',
900	            'F',
901	            => {
902	                if (base != .hex) {
903	                    offset.* = i;
904	                    return false;
905	                }
906	                i += 1;
907	                if (i < str.length()) {
908	                    continue :next str.charAt(i);
909	                }
910	                return true;
911	            },
912	
913	            '1'...'9' => {
914	                i += 1;
915	                if (i < str.length()) {
916	                    continue :next str.charAt(i);
