pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

pub fn parse(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const arg = callframe.argument(0);
    if (arg.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Bun.INI.parse expects a string", .{});
    }

    const bunstr = try arg.toBunString(globalThis);
    defer bunstr.deref();
    const utf8 = bunstr.toUTF8(bun.default_allocator);
    defer utf8.deinit();

    var parser = bun.ini.Parser.init(bun.default_allocator, "input.ini", utf8.slice(), globalThis.bunVM().transpiler.env);
    defer parser.deinit();

    try parser.parse(parser.arena.allocator());

    return parser.out.toJS(bun.default_allocator, globalThis) catch |err| switch (err) {
        error.OutOfMemory => return error.OutOfMemory,
        error.JSError => return error.JSError,
        error.JSTerminated => return error.JSTerminated,
        // INI parsing does not produce macros or identifiers
        else => unreachable,
    };
}

pub fn stringify(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const value = callframe.argument(0);

    if (!value.isObject()) {
        return globalThis.throwInvalidArguments("Bun.INI.stringify expects an object", .{});
    }

    var arena = bun.ArenaAllocator.init(bun.default_allocator);
    defer arena.deinit();
    const allocator = arena.allocator();

    var out = std.ArrayListUnmanaged(u8){};

    // Collect sections (object-valued properties) for the second pass.
    // Scalar and array-valued properties are emitted in the first pass.
    const Section = struct { key: []const u8, val: jsc.JSValue };
    var sections = std.ArrayListUnmanaged(Section){};

    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            globalThis,
            try value.toObject(globalThis),
        );
        defer iter.deinit();

        while (try iter.next()) |key| {
            const prop_value = iter.value;
            const key_str = try key.toOwnedSlice(allocator);

            if (prop_value.isObject() and !prop_value.isArray()) {
                try sections.append(allocator, .{ .key = key_str, .val = prop_value });
            } else {
                try writeKeyValue(globalThis, allocator, &out, key_str, prop_value);
            }
        }
    }

    // Emit [section] headers and their key=value pairs.
    for (sections.items) |section| {
        if (out.items.len > 0) {
            try out.append(allocator, '\n');
        }
        try out.append(allocator, '[');
        try out.appendSlice(allocator, section.key);
        try out.appendSlice(allocator, "]\n");

        var siter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            globalThis,
            try section.val.toObject(globalThis),
        );
        defer siter.deinit();

        while (try siter.next()) |skey| {
            const sval = siter.value;
            const skey_str = try skey.toOwnedSlice(allocator);
            try writeKeyValue(globalThis, allocator, &out, skey_str, sval);
        }
    }

    var result = bun.String.borrowUTF8(out.items);
    defer result.deref();
    return result.toJS(globalThis);
}

fn writeKeyValue(
    globalThis: *jsc.JSGlobalObject,
    allocator: std.mem.Allocator,
    out: *std.ArrayListUnmanaged(u8),
    key: []const u8,
    val: jsc.JSValue,
) bun.JSError!void {
    if (val.isArray()) {
        var iter = try val.arrayIterator(globalThis);
        while (try iter.next()) |elem| {
            try out.appendSlice(allocator, key);
            try out.appendSlice(allocator, "[]=");
            try writeScalarValue(globalThis, allocator, out, elem);
            try out.append(allocator, '\n');
        }
    } else {
        try out.appendSlice(allocator, key);
        try out.append(allocator, '=');
        try writeScalarValue(globalThis, allocator, out, val);
        try out.append(allocator, '\n');
    }
}

fn writeScalarValue(
    globalThis: *jsc.JSGlobalObject,
    allocator: std.mem.Allocator,
    out: *std.ArrayListUnmanaged(u8),
    val: jsc.JSValue,
) bun.JSError!void {
    if (val.isNull() or val.isUndefined()) {
        return;
    }
    var str = try val.toBunString(globalThis);
    defer str.deref();
    const utf8 = str.toUTF8(allocator);
    defer utf8.deinit();
    try out.appendSlice(allocator, utf8.slice());
}

