import { expect, test, describe } from "bun:test";

describe("Bun.INI.parse", () => {
  test("parses basic key=value pairs", () => {
    const result = Bun.INI.parse("foo=bar\nbaz=qux\n");
    expect(result).toEqual({ foo: "bar", baz: "qux" });
  });

  test("parses sections as nested objects", () => {
    const result = Bun.INI.parse("[section]\nkey=value\n");
    expect(result).toEqual({ section: { key: "value" } });
  });

  test("parses multiple sections", () => {
    const result = Bun.INI.parse(
      "[database]\nhost=localhost\nport=5432\n\n[cache]\nttl=300\n",
    );
    expect(result).toEqual({
      database: { host: "localhost", port: 5432 },
      cache: { ttl: 300 },
    });
  });

  test("ignores semicolon comment lines", () => {
    const result = Bun.INI.parse("; this is a comment\nfoo=bar\n");
    expect(result).toEqual({ foo: "bar" });
  });

  test("ignores hash comment lines", () => {
    const result = Bun.INI.parse("# this is a comment\nfoo=bar\n");
    expect(result).toEqual({ foo: "bar" });
  });

  test("ignores inline semicolon comments", () => {
    const result = Bun.INI.parse("foo=bar ; inline comment\n");
    expect(result).toEqual({ foo: "bar" });
  });

  test("coerces 'true' and 'false' strings to booleans", () => {
    const result = Bun.INI.parse("enabled=true\ndisabled=false\n");
    expect(result).toEqual({ enabled: true, disabled: false });
  });

  test("coerces 'null' string to null", () => {
    const result = Bun.INI.parse("value=null\n");
    expect(result).toEqual({ value: null });
  });

  test("coerces numeric string values to numbers", () => {
    const result = Bun.INI.parse("port=8080\ntimeout=30\n");
    expect(result).toEqual({ port: 8080, timeout: 30 });
  });

  test("parses array syntax key[]=value", () => {
    const result = Bun.INI.parse("tags[]=alpha\ntags[]=beta\ntags[]=gamma\n");
    expect(result).toEqual({ tags: ["alpha", "beta", "gamma"] });
  });

  test("parses top-level keys and section together", () => {
    const result = Bun.INI.parse("name=app\n\n[server]\nport=3000\n");
    expect(result).toEqual({ name: "app", server: { port: 3000 } });
  });

  test("throws on non-string input", () => {
    expect(() => Bun.INI.parse(null as any)).toThrow();
    expect(() => Bun.INI.parse(undefined as any)).toThrow();
  });

  test("returns empty object for empty string", () => {
    const result = Bun.INI.parse("");
    expect(result).toEqual({});
  });

  test("handles CRLF line endings", () => {
    const result = Bun.INI.parse("foo=bar\r\nbaz=qux\r\n");
    expect(result).toEqual({ foo: "bar", baz: "qux" });
  });
});

describe("Bun.INI.stringify", () => {
  test("stringifies a flat object", () => {
    const result = Bun.INI.stringify({ foo: "bar", baz: "qux" });
    expect(result).toContain("foo=bar");
    expect(result).toContain("baz=qux");
  });

  test("stringifies boolean values", () => {
    const result = Bun.INI.stringify({ enabled: true, disabled: false });
    expect(result).toContain("enabled=true");
    expect(result).toContain("disabled=false");
  });

  test("stringifies numeric values", () => {
    const result = Bun.INI.stringify({ port: 8080 });
    expect(result).toContain("port=8080");
  });

  test("stringifies nested objects as sections", () => {
    const result = Bun.INI.stringify({ server: { host: "localhost", port: 3000 } });
    expect(result).toContain("[server]");
    expect(result).toContain("host=localhost");
    expect(result).toContain("port=3000");
  });

  test("stringifies mixed flat and nested properties", () => {
    const result = Bun.INI.stringify({ name: "app", server: { port: 3000 } });
    expect(result).toContain("name=app");
    expect(result).toContain("[server]");
    expect(result).toContain("port=3000");
    // flat keys come before sections
    const nameIdx = result.indexOf("name=app");
    const sectionIdx = result.indexOf("[server]");
    expect(nameIdx).toBeLessThan(sectionIdx);
  });

  test("stringifies arrays with bracketed key syntax", () => {
    const result = Bun.INI.stringify({ tags: ["alpha", "beta", "gamma"] });
    expect(result).toContain("tags[]=alpha");
    expect(result).toContain("tags[]=beta");
    expect(result).toContain("tags[]=gamma");
  });

  test("throws on non-object input", () => {
    expect(() => Bun.INI.stringify("string" as any)).toThrow();
    expect(() => Bun.INI.stringify(42 as any)).toThrow();
    expect(() => Bun.INI.stringify(null as any)).toThrow();
  });

  test("round-trip: parse(stringify(obj)) equals original for flat object", () => {
    const original = { foo: "bar", enabled: true, port: 8080 };
    const roundtripped = Bun.INI.parse(Bun.INI.stringify(original));
    expect(roundtripped).toEqual(original);
  });

  test("round-trip: parse(stringify(obj)) equals original for nested object", () => {
    const original = {
      name: "myapp",
      database: { host: "localhost", port: 5432 },
    };
    const roundtripped = Bun.INI.parse(Bun.INI.stringify(original));
    expect(roundtripped).toEqual(original);
  });
});

