// ─── Bun.INI public API ──────────────────────────────────────────────────────

describe("Bun.INI", () => {
  describe("parse", () => {
    test("basic key=value pairs", () => {
      const result = Bun.INI.parse("foo=bar\nbaz=qux\n");
      expect(result).toEqual({ foo: "bar", baz: "qux" });
    });

    test("sections become nested objects", () => {
      const result = Bun.INI.parse("[section]\nkey=value\n");
      expect(result).toEqual({ section: { key: "value" } });
    });

    test("multiple sections", () => {
      const result = Bun.INI.parse("[database]\nhost=localhost\n\n[cache]\nttl=300\n");
      expect(result).toEqual({
        database: { host: "localhost" },
        cache: { ttl: "300" },
      });
    });

    test("ignores semicolon comment lines", () => {
      const result = Bun.INI.parse("; comment\nfoo=bar\n");
      expect(result).toEqual({ foo: "bar" });
    });

    test("ignores hash comment lines", () => {
      const result = Bun.INI.parse("# comment\nfoo=bar\n");
      expect(result).toEqual({ foo: "bar" });
    });

    test("coerces 'true' and 'false' strings to booleans", () => {
      const result = Bun.INI.parse("enabled=true\ndisabled=false\n");
      expect(result).toEqual({ enabled: true, disabled: false });
    });

    test("coerces 'null' string to null", () => {
      const result = Bun.INI.parse("value=null\n");
      expect(result).toEqual({ value: null });
    });

    test("unquoted numeric values remain as strings", () => {
      const result = Bun.INI.parse("port=8080\n");
      expect(result).toEqual({ port: "8080" });
    });

    test("array syntax key[]=value", () => {
      const result = Bun.INI.parse("tags[]=alpha\ntags[]=beta\ntags[]=gamma\n");
      expect(result).toEqual({ tags: ["alpha", "beta", "gamma"] });
    });

    test("top-level keys and sections coexist", () => {
      const result = Bun.INI.parse("name=app\n\n[server]\nhost=localhost\n");
      expect(result).toEqual({ name: "app", server: { host: "localhost" } });
    });

    test("throws on null input", () => {
      expect(() => Bun.INI.parse(null as any)).toThrow();
    });

    test("throws on undefined input", () => {
      expect(() => Bun.INI.parse(undefined as any)).toThrow();
    });

    test("returns empty object for empty string", () => {
      const result = Bun.INI.parse("");
      expect(result).toEqual({});
    });

    test("handles CRLF line endings", () => {
      const result = Bun.INI.parse("foo=bar\r\nbaz=qux\r\n");
      expect(result).toEqual({ foo: "bar", baz: "qux" });
    });
  });

  describe("stringify", () => {
    test("flat object produces key=value lines", () => {
      const result = Bun.INI.stringify({ foo: "bar", baz: "qux" });
      expect(result).toContain("foo=bar\n");
      expect(result).toContain("baz=qux\n");
    });

    test("boolean values", () => {
      const result = Bun.INI.stringify({ enabled: true, disabled: false });
      expect(result).toContain("enabled=true\n");
      expect(result).toContain("disabled=false\n");
    });

    test("numeric values are converted to strings", () => {
      const result = Bun.INI.stringify({ port: 8080 });
      expect(result).toContain("port=8080\n");
    });

    test("null values stringify as 'null'", () => {
      const result = Bun.INI.stringify({ value: null });
      expect(result).toContain("value=null\n");
    });

    test("undefined values are omitted", () => {
      const result = Bun.INI.stringify({ keep: "yes", drop: undefined });
      expect(result).toContain("keep=yes\n");
      expect(result).not.toContain("drop");
    });

    test("nested objects become [section] headers", () => {
      const result = Bun.INI.stringify({ server: { host: "localhost" } });
      expect(result).toContain("[server]\n");
      expect(result).toContain("host=localhost\n");
    });

    test("flat keys appear before sections", () => {
      const result = Bun.INI.stringify({ name: "app", server: { port: "3000" } });
      expect(result).toContain("name=app\n");
      expect(result).toContain("[server]\n");
      expect(result).toContain("port=3000\n");
      expect(result.indexOf("name=app")).toBeLessThan(result.indexOf("[server]"));
    });

    test("sections are separated by a blank line", () => {
      const result = Bun.INI.stringify({ name: "app", server: { host: "localhost" } });
      // There should be a blank line between the flat part and the section
      expect(result).toContain("\n\n[server]");
    });

    test("arrays produce repeated key[]=value lines", () => {
      const result = Bun.INI.stringify({ tags: ["alpha", "beta", "gamma"] });
      expect(result).toContain("tags[]=alpha\n");
      expect(result).toContain("tags[]=beta\n");
      expect(result).toContain("tags[]=gamma\n");
    });

    test("throws on non-object string input", () => {
      expect(() => Bun.INI.stringify("string" as any)).toThrow();
    });

    test("throws on non-object number input", () => {
      expect(() => Bun.INI.stringify(42 as any)).toThrow();
    });

    test("throws on null input", () => {
      expect(() => Bun.INI.stringify(null as any)).toThrow();
    });

    test("round-trip: string values survive parse(stringify(obj))", () => {
      const original = { foo: "bar", greeting: "hello world" };
      const roundtripped = Bun.INI.parse(Bun.INI.stringify(original));
      expect(roundtripped).toEqual(original);
    });

    test("round-trip: boolean values survive parse(stringify(obj))", () => {
      const original = { enabled: true, disabled: false };
      const roundtripped = Bun.INI.parse(Bun.INI.stringify(original));
      expect(roundtripped).toEqual(original);
    });

    test("round-trip: null values survive parse(stringify(obj))", () => {
      const original = { value: null };
      const roundtripped = Bun.INI.parse(Bun.INI.stringify(original));
      expect(roundtripped).toEqual(original);
    });

    test("round-trip: nested string values survive parse(stringify(obj))", () => {
      const original = {
        name: "myapp",
        database: { host: "localhost" },
      };
      const roundtripped = Bun.INI.parse(Bun.INI.stringify(original));
      expect(roundtripped).toEqual(original);
    });
  });
});

