1	pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
2	    const object = JSValue.createEmptyObject(globalThis, 2);
3	    object.put(
4	        globalThis,
5	        ZigString.static("parse"),
6	        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
7	    );
8	    object.put(
9	        globalThis,
10	        ZigString.static("stringify"),
11	        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
12	    );
13	    return object;
14	}
15	
16	pub fn parse(
17	    globalThis: *jsc.JSGlobalObject,
18	    callframe: *jsc.CallFrame,
19	) bun.JSError!jsc.JSValue {
20	    const arg = callframe.argument(0);
21	    if (arg.isEmptyOrUndefinedOrNull()) {
22	        return globalThis.throwInvalidArguments("Bun.INI.parse expects a string", .{});
23	    }
24	
25	    const bunstr = try arg.toBunString(globalThis);
26	    defer bunstr.deref();
27	    const utf8 = bunstr.toUTF8(bun.default_allocator);
28	    defer utf8.deinit();
29	
30	    var parser = bun.ini.Parser.init(bun.default_allocator, "input.ini", utf8.slice(), globalThis.bunVM().transpiler.env);
31	    defer parser.deinit();
32	
33	    try parser.parse(parser.arena.allocator());
34	
35	    return parser.out.toJS(bun.default_allocator, globalThis) catch |err| switch (err) {
36	        error.OutOfMemory => return error.OutOfMemory,
37	        error.JSError => return error.JSError,
38	        error.JSTerminated => return error.JSTerminated,
39	        // INI parsing does not produce macros or identifiers
40	        else => unreachable,
41	    };
42	}
43	
44	pub fn stringify(
45	    globalThis: *jsc.JSGlobalObject,
46	    callframe: *jsc.CallFrame,
47	) bun.JSError!jsc.JSValue {
48	    const value = callframe.argument(0);
49	
50	    if (!value.isObject()) {
51	        return globalThis.throwInvalidArguments("Bun.INI.stringify expects an object", .{});
52	    }
53	
54	    var arena = bun.ArenaAllocator.init(bun.default_allocator);
55	    defer arena.deinit();
56	    const allocator = arena.allocator();
57	
58	    var out = std.ArrayListUnmanaged(u8){};
59	
60	    // Collect sections (object-valued properties) for the second pass.
61	    // Scalar and array-valued properties are emitted in the first pass.
62	    const Section = struct { key: []const u8, val: jsc.JSValue };
63	    var sections = std.ArrayListUnmanaged(Section){};
64	
65	    {
66	        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
67	            globalThis,
68	            try value.toObject(globalThis),
69	        );
70	        defer iter.deinit();
71	
72	        while (try iter.next()) |key| {
73	            const prop_value = iter.value;
74	            const key_str = try key.toOwnedSlice(allocator);
75	
76	            if (prop_value.isObject() and !prop_value.isArray()) {
77	                try sections.append(allocator, .{ .key = key_str, .val = prop_value });
78	            } else {
79	                try writeKeyValue(globalThis, allocator, &out, key_str, prop_value);
80	            }
81	        }
82	    }
83	
84	    // Emit [section] headers and their key=value pairs.
85	    for (sections.items) |section| {
86	        if (out.items.len > 0) {
87	            try out.append(allocator, '\n');
88	        }
89	        try out.append(allocator, '[');
90	        try out.appendSlice(allocator, section.key);
91	        try out.appendSlice(allocator, "]\n");
92	
93	        var siter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
94	            globalThis,
95	            try section.val.toObject(globalThis),
96	        );
97	        defer siter.deinit();
98	
99	        while (try siter.next()) |skey| {
100	            const sval = siter.value;
101	            const skey_str = try skey.toOwnedSlice(allocator);
102	            try writeKeyValue(globalThis, allocator, &out, skey_str, sval);
103	        }
104	    }
105	
106	    var result = bun.String.borrowUTF8(out.items);
107	    defer result.deref();
108	    return result.toJS(globalThis);
109	}
110	
111	fn writeKeyValue(
112	    globalThis: *jsc.JSGlobalObject,
113	    allocator: std.mem.Allocator,
114	    out: *std.ArrayListUnmanaged(u8),
115	    key: []const u8,
116	    val: jsc.JSValue,
117	) bun.JSError!void {
118	    // Skip undefined values entirely — don't emit the key at all.
119	    if (val.isUndefined()) return;
120	
121	    if (val.isArray()) {
122	        var iter = try val.arrayIterator(globalThis);
123	        while (try iter.next()) |elem| {
124	            try out.appendSlice(allocator, key);
125	            try out.appendSlice(allocator, "[]=");
126	            try writeScalarValue(globalThis, allocator, out, elem);
127	            try out.append(allocator, '\n');
128	        }
129	    } else {
130	        try out.appendSlice(allocator, key);
